def load_config(config_path: Optional[Path] = None) -> AscendConfig:
    """Load config from YAML, falling back to defaults."""
    path = config_path or CONFIG_PATH
    if path.exists():
        with open(path) as f:
            raw = yaml.safe_load(f) or {}
        return AscendConfig(**{k: v for k, v in raw.items() if v is not None})
    return AscendConfig()

def get_config_value(key: str, cfg: Optional[AscendConfig] = None) -> str:
    """Get a single config value by key."""
    if cfg is None:
        cfg = load_config()
    data = cfg.model_dump()
    if key not in data:
        raise KeyError(f"Unknown config key: {key}")
    return str(data[key])

def init_db(db_path: Path) -> sqlite3.Connection:
    """Create the database and apply the schema."""
    db_path.parent.mkdir(parents=True, exist_ok=True)
    conn = get_connection(db_path)

    # Check current version
    try:
        row = conn.execute(
            "SELECT MAX(version) FROM schema_version"
        ).fetchone()
        current = row[0] if row and row[0] else 0
    except sqlite3.OperationalError:
        current = 0

    if current < SCHEMA_VERSION:
        conn.executescript(_SCHEMA_SQL)
        conn.execute(
            "INSERT INTO schema_version (version) VALUES (?)",
            (SCHEMA_VERSION,),
        )
        conn.commit()

    return conn

def check_db(db_path: Path) -> dict:
    """Health check — returns table counts and version."""
    if not db_path.exists():
        return {"ok": False, "error": "Database not found"}

    conn = get_connection(db_path)
    try:
        row = conn.execute(
            "SELECT MAX(version) FROM schema_version"
        ).fetchone()
        version = row[0] if row and row[0] else 0
    except sqlite3.OperationalError:
        return {"ok": False, "error": "Schema not initialized"}

    tables = [
        "members", "member_flags", "teams", "team_members",
        "meetings", "meeting_items", "goals",
        "performance_snapshots", "coaching_entries", "schedules",
    ]
    counts = {}
    for table in tables:
        row = conn.execute(f"SELECT COUNT(*) FROM {table}").fetchone()
        counts[table] = row[0]

    conn.close()
    return {
        "ok": True,
        "version": version,
        "tables": counts,
    }

def _colorize(text: str) -> str:
    """Apply ANSI colors to markdown-formatted report text."""
    lines = []
    for line in text.split("\n"):
        if line.startswith("# ") or line.startswith("## "):
            lines.append(f"{_BOLD}{_CYAN}{line}{_RESET}")
        elif line.startswith("### "):
            lines.append(f"{_BOLD}{line}{_RESET}")
        elif "Blocked" in line:
            lines.append(f"{_RED}{line}{_RESET}")
        elif "Active" in line or "On Track" in line:
            lines.append(f"{_GREEN}{line}{_RESET}")
        elif "At Risk" in line:
            lines.append(f"{_YELLOW}{line}{_RESET}")
        elif line.startswith("Generated:") or line.startswith("---"):
            lines.append(f"{_DIM}{line}{_RESET}")
        else:
            lines.append(line)
    return "\n".join(lines)

def print_report(text: str, *, use_color: bool | None = None) -> None:
    """Print report text, with optional ANSI coloring for TTY."""
    if use_color is None:
        use_color = sys.stdout.isatty()
    output = _colorize(text) if use_color else text
    print(output)

def print_json(data: Any) -> None:
    """Print data as formatted JSON to stdout."""
    print(json.dumps(data, indent=2, default=str))

def print_status(message: str) -> None:
    """Print a status message to stderr (doesn't interfere with piped stdout)."""
    if sys.stderr.isatty():
        sys.stderr.write(f"{_DIM}{message}{_RESET}\n")
    else:
        sys.stderr.write(f"{message}\n")

def copy_to_clipboard(text: str) -> bool:
    """Copy text to clipboard via pbcopy (macOS)."""
    try:
        proc = subprocess.run(
            ["pbcopy"],
            input=text.encode("utf-8"),
            timeout=5,
        )
        return proc.returncode == 0
    except (subprocess.TimeoutExpired, FileNotFoundError, OSError):
        return False

def format_table(headers: list[str], rows: list[list[str]]) -> str:
    """Format data as a markdown table."""
    if not rows:
        return "No data."

    # Calculate column widths
    widths = [len(h) for h in headers]
    for row in rows:
        for i, cell in enumerate(row):
            if i < len(widths):
                widths[i] = max(widths[i], len(str(cell)))

    # Build table
    lines = []
    header_line = "| " + " | ".join(h.ljust(w) for h, w in zip(headers, widths)) + " |"
    sep_line = "|-" + "-|-".join("-" * w for w in widths) + "-|"
    lines.append(header_line)
    lines.append(sep_line)
    for row in rows:
        cells = []
        for i, w in enumerate(widths):
            cell = str(row[i]) if i < len(row) else ""
            cells.append(cell.ljust(w))
        lines.append("| " + " | ".join(cells) + " |")
    return "\n".join(lines)

def render_output(data: Any, *, json_mode: bool = False, copy: bool = False) -> None:
    """Unified output handler. JSON mode prints raw JSON; otherwise markdown."""
    if json_mode:
        text = json.dumps(data, indent=2, default=str)
        print(text)
        if copy:
            copy_to_clipboard(text)
    elif isinstance(data, str):
        print_report(data)
        if copy:
            copy_to_clipboard(data)
    else:
        text = json.dumps(data, indent=2, default=str)
        print(text)
        if copy:
            copy_to_clipboard(text)

def _expand_field(field: str, min_val: int, max_val: int) -> set[int]:
    """Expand a cron field into a set of integer values."""
    if field == "*":
        return set(range(min_val, max_val + 1))
    values: set[int] = set()
    for part in field.split(","):
        if "-" in part:
            start, end = part.split("-", 1)
            values.update(range(int(start), int(end) + 1))
        else:
            values.add(int(part))
    return values

def describe_cron(cron_expr: str) -> str:
    """Return a human-readable description of a cron expression."""
    fields = parse_cron(cron_expr)

    time_str = f"{int(fields['hour']):02d}:{int(fields['minute']):02d}" if fields["hour"] != "*" else ""

    if fields["dom"] == "*" and fields["month"] == "*" and fields["dow"] == "*":
        return f"daily at {time_str}" if time_str else "every minute"

    if fields["dom"] == "*" and fields["month"] == "*" and fields["dow"] == "1-5":
        return f"weekdays at {time_str}" if time_str else "weekdays"

    if fields["dom"] == "*" and fields["month"] == "*" and fields["dow"] != "*":
        day_names = {0: "Sun", 1: "Mon", 2: "Tue", 3: "Wed", 4: "Thu", 5: "Fri", 6: "Sat"}
        dows = _expand_field(fields["dow"], 0, 6)
        days = ", ".join(day_names.get(d, str(d)) for d in sorted(dows))
        return f"every {days} at {time_str}" if time_str else f"every {days}"

    if fields["dow"] == "*" and fields["month"] == "*":
        return f"monthly on day(s) {fields['dom']} at {time_str}" if time_str else f"monthly on {fields['dom']}"

    if fields["month"] != "*" and fields["dom"] != "*":
        return f"on day {fields['dom']} of months {fields['month']} at {time_str}"

    return cron_expr

def _find_ascend_path() -> str:
    """Find the ascend executable path."""
    path = shutil.which("ascend")
    if path:
        return path
    # Fallback: try common locations
    for candidate in ["/usr/local/bin/ascend", str(Path.home() / ".local/bin/ascend")]:
        if Path(candidate).exists():
            return candidate
    return "ascend"

def _cron_to_calendar_intervals(cron_expr: str) -> str:
    """Convert cron expression to launchd CalendarInterval XML."""
    fields = parse_cron(cron_expr)
    intervals = []

    minutes = _expand_field(fields["minute"], 0, 59)
    hours = _expand_field(fields["hour"], 0, 23)

    # For simple cases, generate one or a few intervals
    minute_val = min(minutes) if len(minutes) <= 2 else 0
    hour_val = min(hours) if len(hours) <= 2 else 9

    if fields["dom"] == "*" and fields["month"] == "*" and fields["dow"] == "*":
        # Daily
        intervals.append({"Hour": hour_val, "Minute": minute_val})
    elif fields["dow"] == "1-5":
        # Weekdays
        for dow in range(1, 6):
            intervals.append({"Weekday": dow, "Hour": hour_val, "Minute": minute_val})
    elif fields["dow"] != "*" and fields["dom"] == "*":
        # Specific weekdays
        for dow in _expand_field(fields["dow"], 0, 6):
            intervals.append({"Weekday": dow, "Hour": hour_val, "Minute": minute_val})
    elif fields["dom"] != "*" and fields["month"] != "*":
        # Specific months and days
        for month in _expand_field(fields["month"], 1, 12):
            for day in _expand_field(fields["dom"], 1, 31):
                intervals.append({"Month": month, "Day": day, "Hour": hour_val, "Minute": minute_val})
    elif fields["dom"] != "*":
        # Specific days of month
        for day in _expand_field(fields["dom"], 1, 31):
            intervals.append({"Day": day, "Hour": hour_val, "Minute": minute_val})
    else:
        intervals.append({"Hour": hour_val, "Minute": minute_val})

    # Build XML
    if len(intervals) == 1:
        xml = "    <dict>\n"
        for k, v in intervals[0].items():
            xml += f"        <key>{k}</key>\n        <integer>{v}</integer>\n"
        xml += "    </dict>"
    else:
        xml = "    <array>\n"
        for interval in intervals:
            xml += "        <dict>\n"
            for k, v in interval.items():
                xml += f"            <key>{k}</key>\n            <integer>{v}</integer>\n"
            xml += "        </dict>\n"
        xml += "    </array>"
    return xml

def load_plist(schedule_name: str) -> bool:
    """Load a launchd plist. Returns True on success."""
    label = f"com.ascend.schedule.{schedule_name}"
    plist_path = Path.home() / "Library" / "LaunchAgents" / f"{label}.plist"
    if not plist_path.exists():
        return False
    try:
        subprocess.run(["launchctl", "load", str(plist_path)], capture_output=True, timeout=10)
        return True
    except Exception:
        return False

def unload_plist(schedule_name: str) -> bool:
    """Unload a launchd plist. Returns True on success."""
    label = f"com.ascend.schedule.{schedule_name}"
    plist_path = Path.home() / "Library" / "LaunchAgents" / f"{label}.plist"
    if not plist_path.exists():
        return False
    try:
        subprocess.run(["launchctl", "unload", str(plist_path)], capture_output=True, timeout=10)
        return True
    except Exception:
        return False

def _truncate(text: str) -> str:
    if len(text) <= _MAX_INPUT_CHARS:
        return text
    truncated = text[:_MAX_INPUT_CHARS]
    last_period = truncated.rfind(". ")
    if last_period > _MAX_INPUT_CHARS // 2:
        truncated = truncated[:last_period + 1]
    return truncated + " [TRUNCATED]"

def _parse_json(text: str) -> Any:
    stripped = text.strip()
    fence_pattern = re.compile(r"^```(?:json)?\s*\n?(.*?)\n?\s*```$", re.DOTALL)
    m = fence_pattern.match(stripped)
    if m:
        stripped = m.group(1).strip()
    return json.loads(stripped)

def get_client(config: AscendConfig) -> Optional[anthropic.Anthropic]:
    """Create an anthropic client from env var. Returns None if unavailable."""
    try:
        api_key = os.environ.get(config.anthropic_api_key_env, "")
        if not api_key:
            logger.warning("API key env var '%s' is not set or empty", config.anthropic_api_key_env)
            return None
        return anthropic.Anthropic(api_key=api_key)
    except Exception:
        logger.error("Unexpected error creating Anthropic client", exc_info=True)
        return None

def summarize_transcript(
    raw_text: str,
    config: AscendConfig,
    client: Optional[anthropic.Anthropic] = None,
) -> Optional[str]:
    """Summarize a meeting transcript. Returns None on any failure."""
    try:
        if not raw_text or not raw_text.strip():
            return None
        if client is None:
            client = get_client(config)
        if client is None:
            return None

        response = client.messages.create(
            model=config.model, max_tokens=4096,
            system=_SUMMARY_SYSTEM_PROMPT,
            messages=[{"role": "user", "content": _truncate(raw_text)}],
        )
        result = response.content[0].text
        log_operation("summarize_transcript", result="success")
        return result if result else None
    except Exception:
        logger.error("Error in summarize_transcript", exc_info=True)
        log_operation("summarize_transcript", error="failed")
        return None

def extract_items(
    raw_text: str,
    config: AscendConfig,
    client: Optional[anthropic.Anthropic] = None,
) -> list[dict[str, Any]]:
    """Extract structured meeting items. Returns [] on any failure."""
    try:
        if not raw_text or not raw_text.strip():
            return []
        if client is None:
            client = get_client(config)
        if client is None:
            return []

        response = client.messages.create(
            model=config.model, max_tokens=4096,
            system=_EXTRACT_SYSTEM_PROMPT,
            messages=[{"role": "user", "content": _truncate(raw_text)}],
        )
        try:
            parsed = _parse_json(response.content[0].text)
        except (json.JSONDecodeError, ValueError):
            logger.warning("Malformed JSON response from Claude in extract_items")
            return []

        if not isinstance(parsed, list):
            return []

        items: list[dict[str, Any]] = []
        for raw_item in parsed:
            if not isinstance(raw_item, dict):
                continue
            try:
                validated = MeetingItemExtract(**raw_item)
                items.append(validated.model_dump())
            except Exception:
                logger.warning("Dropping invalid item: %s", raw_item)
        log_operation("extract_items", result=f"extracted {len(items)} items")
        return items
    except Exception:
        logger.error("Error in extract_items", exc_info=True)
        return []

def analyze_sentiment(
    raw_text: str,
    config: AscendConfig,
    client: Optional[anthropic.Anthropic] = None,
) -> Optional[float]:
    """Analyze sentiment. Returns float in [0.0, 1.0] or None."""
    try:
        if not raw_text or not raw_text.strip():
            return None
        if client is None:
            client = get_client(config)
        if client is None:
            return None

        response = client.messages.create(
            model=config.model, max_tokens=256,
            system=_SENTIMENT_SYSTEM_PROMPT,
            messages=[{"role": "user", "content": _truncate(raw_text)}],
        )
        raw_response = response.content[0].text
        score = None
        try:
            parsed = _parse_json(raw_response)
            if isinstance(parsed, dict) and "score" in parsed:
                score = float(parsed["score"])
            elif isinstance(parsed, (int, float)):
                score = float(parsed)
        except (json.JSONDecodeError, ValueError, TypeError):
            try:
                score = float(raw_response.strip())
            except (ValueError, TypeError):
                return None

        if score is None:
            return None
        if score < 0.0 or score > 1.0:
            logger.warning("Sentiment score %.4f out of range, clamping", score)
            score = max(0.0, min(1.0, score))

        log_operation("analyze_sentiment", result="success")
        return score
    except Exception:
        logger.error("Error in analyze_sentiment", exc_info=True)
        return None

def generate_prep(
    member_name: str,
    recent_meetings: list[dict],
    open_items: list[dict],
    performance_data: Optional[dict] = None,
    config: Optional[AscendConfig] = None,
    client: Optional[anthropic.Anthropic] = None,
) -> Optional[str]:
    """Generate a 1:1 prep plan. Returns None on any failure."""
    try:
        if not member_name or not member_name.strip():
            return None
        if config is None:
            from ascend.config import load_config
            config = load_config()
        if client is None:
            client = get_client(config)
        if client is None:
            return None

        parts = [f"Prepare for an upcoming 1:1 meeting with {member_name.strip()}."]

        if recent_meetings:
            parts.append("\n## Recent Meetings")
            for mtg in recent_meetings:
                parts.append(f"\n### {mtg.get('date', 'Unknown date')}")
                if mtg.get("summary"):
                    parts.append(f"Summary: {mtg['summary']}")
                for item in mtg.get("items", []):
                    parts.append(f"- [{item.get('kind', '?')}] {item.get('content', '')}")

        if open_items:
            parts.append("\n## Open Action Items")
            for item in open_items:
                parts.append(f"- {item.get('content', '')} (from {item.get('date', '?')})")

        if performance_data:
            parts.append("\n## Performance Data")
            if performance_data.get("goals"):
                parts.append("Goals: " + "; ".join(performance_data["goals"]))
            if performance_data.get("flags"):
                parts.append("Flags: " + "; ".join(performance_data["flags"]))
            if performance_data.get("notes"):
                parts.append(f"Notes: {performance_data['notes']}")

        response = client.messages.create(
            model=config.model, max_tokens=4096,
            system=_PREP_SYSTEM_PROMPT,
            messages=[{"role": "user", "content": _truncate("\n".join(parts))}],
        )
        result = response.content[0].text
        log_operation("generate_prep", result="success")
        return result if result else None
    except Exception:
        logger.error("Error in generate_prep", exc_info=True)
        return None

def content_must_be_nonempty(cls, v: str) -> str:
    if not v:
        raise ValueError("content must be non-empty")
    return v

def parse_transcript(file_path: Path) -> ParsedTranscript:
    """Read a transcript file and parse it into a ParsedTranscript."""
    if not file_path.exists():
        raise TranscriptError(f"File not found: {file_path}", TranscriptError.FILE_NOT_FOUND)

    if not file_path.is_file():
        raise TranscriptError(f"Not a file: {file_path}", TranscriptError.INVALID_FORMAT)

    try:
        raw_text = file_path.read_text(encoding="utf-8", errors="replace")
    except (PermissionError, OSError) as exc:
        raise TranscriptError(f"Cannot read file: {file_path}: {exc}", TranscriptError.FILE_UNREADABLE) from exc

    if not raw_text.strip():
        raise TranscriptError(f"Empty transcript: {file_path}", TranscriptError.EMPTY_TRANSCRIPT)

    if len(raw_text) > MAX_RAW_TEXT:
        logger.warning("Transcript %s exceeds %d chars, truncating", file_path.name, MAX_RAW_TEXT)
        raw_text = raw_text[:MAX_RAW_TEXT]

    turns: list[TranscriptTurn] = []
    for line in raw_text.splitlines():
        match = SPEAKER_PATTERN.match(line)
        if match:
            speaker = match.group(1).strip()
            text = match.group(2).strip()
            turns.append(TranscriptTurn(speaker=speaker, text=text))
        else:
            stripped = line.strip()
            if stripped and turns:
                prev = turns[-1]
                turns[-1] = TranscriptTurn(speaker=prev.speaker, text=prev.text + "\n" + stripped)

    filename = file_path.name
    date = detect_date(filename, raw_text)

    member_name: Optional[str] = None
    fn_match = FILENAME_DATE_PATTERN.match(filename)
    if fn_match and fn_match.group(2):
        member_name = fn_match.group(2).replace("_", " ")

    return ParsedTranscript(
        source_file=filename, raw_text=raw_text, turns=turns,
        date=date, member_name=member_name, member_id=None,
    )

def detect_date(filename: str, content: str) -> Optional[str]:
    """Extract a meeting date from filename or content."""
    fn_match = re.match(r'^(\d{4}-\d{2}-\d{2})', filename)
    if fn_match:
        candidate = fn_match.group(1)
        if _validate_date(candidate):
            return candidate

    lines = content.splitlines()[:20]
    for line in lines:
        match = CONTENT_DATE_PATTERN.search(line)
        if match:
            candidate = match.group(1)
            if _validate_date(candidate):
                return candidate
    return None

def resolve_member(
    speaker_names: list[str],
    manager_name: Optional[str],
    db_conn: sqlite3.Connection,
) -> Optional[int]:
    """Match speaker names against members DB to find the meeting subject."""
    try:
        rows = db_conn.execute("SELECT id, name, email, slack FROM members").fetchall()
    except sqlite3.Error as exc:
        raise TranscriptError(f"Database error: {exc}", TranscriptError.INVALID_FORMAT) from exc

    members = []
    for row in rows:
        mid = row[0] if isinstance(row, tuple) else row["id"]
        name = row[1] if isinstance(row, tuple) else row["name"]
        email = row[2] if isinstance(row, tuple) else row["email"]
        slack = row[3] if isinstance(row, tuple) else row["slack"]
        email_prefix = email.split("@")[0] if email else None
        members.append({
            "id": mid, "name": name,
            "name_lower": name.lower(),
            "email_prefix": email_prefix.lower() if email_prefix else None,
            "slack": slack.lower() if slack else None,
        })

    manager_lower = manager_name.lower() if manager_name else None

    for speaker in speaker_names:
        speaker_lower = speaker.lower()
        for m in members:
            if manager_lower and m["name_lower"] == manager_lower:
                continue
            if (speaker_lower == m["name_lower"]
                    or speaker_lower == m["email_prefix"]
                    or speaker_lower == m["slack"]):
                return m["id"]

    for speaker in speaker_names:
        speaker_lower = speaker.lower()
        for m in members:
            if manager_lower and m["name_lower"] == manager_lower:
                continue
            ratio = SequenceMatcher(None, speaker_lower, m["name_lower"]).ratio()
            if ratio >= FUZZY_THRESHOLD:
                return m["id"]

    return None

def scan_directory(dir_path: Path) -> list[Path]:
    """Find all transcript files (.txt, .md) in a directory (non-recursive)."""
    if not dir_path.exists():
        raise TranscriptError(f"Directory not found: {dir_path}", TranscriptError.DIRECTORY_NOT_FOUND)
    if not dir_path.is_dir():
        raise TranscriptError(f"Not a directory: {dir_path}", TranscriptError.DIRECTORY_NOT_FOUND)

    result: list[Path] = []
    for entry in dir_path.iterdir():
        if not entry.is_file():
            continue
        if entry.name.startswith("."):
            continue
        if entry.suffix.lower() not in (".txt", ".md"):
            continue
        if entry.stat().st_size == 0:
            continue
        result.append(entry)

    result.sort(key=lambda p: p.name)
    return result

def check_duplicate(
    source_file: str,
    member_id: Optional[int],
    date: Optional[str],
    db_conn: sqlite3.Connection,
) -> bool:
    """Check if a transcript has already been ingested."""
    try:
        row = db_conn.execute(
            "SELECT COUNT(*) FROM meetings WHERE source_file = ? AND member_id IS ? AND date IS ?",
            (source_file, member_id, date),
        ).fetchone()
    except sqlite3.Error as exc:
        raise TranscriptError(f"Database error: {exc}", TranscriptError.INVALID_FORMAT) from exc
    return row[0] > 0

def _validate_date(candidate: str) -> bool:
    try:
        datetime.date.fromisoformat(candidate)
        return True
    except ValueError:
        return False

def __init__(self, message: str, variant: str) -> None:
