def _show_meeting_detail(self, meeting_id: int) -> None:
    from ascend.config import DB_PATH
    from ascend.db import get_connection

    if not DB_PATH.exists():
        return

    conn = get_connection(DB_PATH)
    try:
        row = conn.execute(
            """SELECT m.*, mem.name as member_name FROM meetings m
               LEFT JOIN members mem ON mem.id = m.member_id
               WHERE m.id = ?""",
            (meeting_id,),
        ).fetchone()
        if not row:
            return

        items = conn.execute(
            "SELECT kind, content, status FROM meeting_items WHERE meeting_id = ? ORDER BY kind, id",
            (meeting_id,),
        ).fetchall()
    finally:
        conn.close()

    parts = [f"## Meeting {row['id']} — {row['date']}"]
    if row["member_name"]:
        parts.append(f"**Member:** {row['member_name']}")
    if row["sentiment_score"] is not None:
        parts.append(f"**Sentiment:** {row['sentiment_score']:.2f}")
    if row["summary"]:
        parts.append(f"\n### Summary\n\n{row['summary']}")
    if items:
        parts.append("\n### Items\n")
        for item in items:
            status = "x" if item["status"] == "closed" else " "
            parts.append(f"- [{status}] **{item['kind']}**: {item['content']}")
    if row["raw_text"]:
        text = row["raw_text"][:3000]
        parts.append(f"\n### Transcript\n\n{text}")
        if len(row["raw_text"]) > 3000:
            parts.append(f"\n*... ({len(row['raw_text'])} chars total)*")

    md = self.query_one("#meeting-detail", Markdown)
    md.update("\n".join(parts))

def _build_git_report(self, conn, from_date: str, to_date: str) -> None:
    members = [
        dict(r)
        for r in conn.execute(
            "SELECT * FROM members WHERE status = 'active' AND github IS NOT NULL ORDER BY name"
        ).fetchall()
    ]

    if not members:
        self.query_one("#report-git", Markdown).update("*No members with GitHub handles*")
        return

    parts = [f"# Git Report — {from_date} to {to_date}\n"]
    parts.append("| Member | GitHub | Commits | PRs Opened | PRs Merged |")
    parts.append("|--------|--------|---------|------------|------------|")

    for m in members:
        snapshots = conn.execute(
            """SELECT metrics FROM performance_snapshots
               WHERE member_id = ? AND date >= ? AND date <= ?""",
            (m["id"], from_date, to_date),
        ).fetchall()

        commits = 0
        prs_opened = 0
        prs_merged = 0
        for s in snapshots:
            met = json.loads(s["metrics"]) if s["metrics"] else {}
            commits += met.get("commits_count", 0)
            prs_opened += met.get("prs_opened", 0)
            prs_merged += met.get("prs_merged", 0)

        parts.append(
            f"| {m['name']} | @{m['github']} | {commits} | {prs_opened} | {prs_merged} |"
        )

    self.query_one("#report-git", Markdown).update("\n".join(parts))

