        i for i in all_issues
        if _assignee_matches(i, member_lower)
    ]

def match_issues(
    issues: list[dict[str, Any]],
    labels: list[str],
    assignees: list[str] | None = None,
) -> list[dict[str, Any]]:
    """Filter issues by label, assignee, or title keyword match."""
    matched = []
    for issue in issues:
        issue_labels = [
            n.get("name", "").lower()
            for n in issue.get("labels", {}).get("nodes", [])
        ]
        # Label match (strongest)
        if any(l.lower() in issue_labels for l in labels):
            matched.append(issue)
            continue

        assignee = issue.get("assignee") or {}
        display = (assignee.get("displayName") or "").lower()
        name = (assignee.get("name") or "").lower()
        has_assignee = bool(display or name)

        # Assignee match
        is_our_assignee = False
        if assignees:
            for a in assignees:
                if a.lower() in (display, name):
                    is_our_assignee = True
                    break
        if is_our_assignee:
            matched.append(issue)
            continue

        # Title keyword (weak, gated)
        if has_assignee and assignees and not is_our_assignee:
            continue
        title = issue.get("title", "").lower()
        if any(l.lower() in title for l in labels):
            matched.append(issue)

    return matched

def fetch_stale_priority_issues(
    api_key: str,
    team_ids: list[str],
    stale_hours: int = 48,
) -> list[dict[str, Any]]:
    """Fetch high-priority/urgent active issues that have gone stale.

    An issue is stale if updatedAt is older than stale_hours ago.
    """
    from datetime import timedelta as _td, timezone

    cutoff = datetime.now(timezone.utc) - _td(hours=stale_hours)
    all_stale: list[dict[str, Any]] = []

    for team_id in team_ids:
        cursor = None
        while True:
            variables: dict[str, Any] = {"teamId": team_id, "first": 50}
            if cursor:
                variables["cursor"] = cursor
            result = _graphql(api_key, _STALE_PRIORITY_QUERY, variables)
            if result is None:
                break
            issues_data = result.get("issues", {})
            for issue in issues_data.get("nodes", []):
                updated = issue.get("updatedAt", "")
                if not updated:
                    continue
                try:
                    updated_dt = datetime.fromisoformat(
                        updated.replace("Z", "+00:00")
                    )
                    if updated_dt < cutoff:
                        hours_stale = (
                            datetime.now(timezone.utc) - updated_dt
                        ).total_seconds() / 3600
                        assignee = issue.get("assignee") or {}
                        all_stale.append({
                            "identifier": issue.get("identifier", ""),
                            "title": issue.get("title", ""),
                            "priority": issue.get("priority", 0),
                            "priority_name": _PRIORITY_NAMES.get(
                                issue.get("priority", 0), "Unknown"
                            ),
                            "state": (issue.get("state") or {}).get("name", ""),
                            "assignee_name": (
                                assignee.get("displayName")
                                or assignee.get("name")
                                or None
                            ),
                            "labels": [
                                n.get("name", "")
                                for n in issue.get("labels", {}).get("nodes", [])
                            ],
                            "updated_at": updated,
                            "hours_stale": round(hours_stale, 1),
                            "url": issue.get("url", ""),
                        })
                except (ValueError, TypeError):
                    continue
            page_info = issues_data.get("pageInfo", {})
            if page_info.get("hasNextPage") and page_info.get("endCursor"):
                cursor = page_info["endCursor"]
            else:
                break

    # Deduplicate by identifier (same issue may appear from multiple teams)
    seen: set[str] = set()
    deduped: list[dict[str, Any]] = []
    for item in all_stale:
        ident = item["identifier"]
        if ident not in seen:
            seen.add(ident)
            deduped.append(item)

    # Sort by staleness descending
    deduped.sort(key=lambda x: x["hours_stale"], reverse=True)
    return deduped

def _assignee_matches(issue: dict[str, Any], name_lower: str) -> bool:
    """Check if issue assignee matches a member name (case-insensitive)."""
    assignee = issue.get("assignee") or {}
    display = (assignee.get("displayName") or "").lower()
    name = (assignee.get("name") or "").lower()
    return name_lower in (display, name) or name_lower in display or name_lower in name

def _api(
    token: str, method: str, params: dict[str, Any] | None = None,
    *, max_retries: int = 2, timeout: int = 15,
) -> dict[str, Any] | None:
    """Call a Slack Web API method with retry."""
    url = f"https://slack.com/api/{method}"
    if params:
        parts = [f"{k}={quote(str(v), safe=',')}" for k, v in params.items()]
        url = f"{url}?{'&'.join(parts)}"

    req = Request(url, headers={
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/x-www-form-urlencoded",
    })

    for attempt in range(max_retries + 1):
        try:
            response = urlopen(req, timeout=timeout)
            return json.loads(response.read().decode())
        except HTTPError as e:
            if e.code == 429:
                retry_after = int(e.headers.get("Retry-After", 2 ** attempt))
                time.sleep(retry_after)
                continue
            return None
        except (URLError, json.JSONDecodeError, OSError):
            if attempt < max_retries:
                time.sleep(2 ** attempt)
                continue
            return None
    return None

def resolve_channel_id(token: str, channel_name: str) -> str | None:
    """Resolve a channel name to its ID."""
    clean = channel_name.lstrip("#")
    cursor = None

    while True:
        params: dict[str, Any] = {
            "types": "public_channel,private_channel",
            "limit": 200, "exclude_archived": "true",
        }
        if cursor:
            params["cursor"] = cursor
        result = _api(token, "users.conversations", params)
        if result is None or not result.get("ok"):
            return None
        for ch in result.get("channels", []):
            if ch.get("name") == clean:
                return ch["id"]
        next_cursor = result.get("response_metadata", {}).get("next_cursor", "")
        if next_cursor:
            cursor = next_cursor
        else:
            return None

def fetch_channel_activity(
    token: str, channel_name: str, since: datetime
) -> dict[str, Any]:
    """Fetch Slack activity for a channel."""
    if not token:
        return {"error": "SLACK_BOT_TOKEN not set", "channel": channel_name,
                "message_count": 0, "active_threads": 0, "notable": []}
    if not channel_name:
        return {"error": "no channel configured", "channel": "",
                "message_count": 0, "active_threads": 0, "notable": []}

    channel_id = resolve_channel_id(token, channel_name)
    if not channel_id:
        return {"error": f"channel not found: #{channel_name}", "channel": channel_name,
                "message_count": 0, "active_threads": 0, "notable": []}

    oldest = str(since.timestamp())
    all_messages: list[dict[str, Any]] = []
    cursor = None

    while True:
        params: dict[str, Any] = {
            "channel": channel_id, "oldest": oldest, "limit": 200, "inclusive": "true",
        }
        if cursor:
            params["cursor"] = cursor
        result = _api(token, "conversations.history", params)
        if result is None or not result.get("ok"):
            error = result.get("error", "unknown") if result else "no response"
            return {"error": error, "channel": channel_name,
                    "message_count": len(all_messages), "active_threads": 0, "notable": []}
        all_messages.extend(result.get("messages", []))
        next_cursor = result.get("response_metadata", {}).get("next_cursor", "")
        if next_cursor:
            cursor = next_cursor
        else:
            break

    # Filter bot/system messages
    real = [m for m in all_messages
            if m.get("subtype") not in ("channel_join", "channel_leave", "bot_message")]
    active_threads = sum(1 for m in real if m.get("reply_count", 0) > 2)
    notable = _extract_notable(real)

    return {
        "error": None, "channel": channel_name,
        "message_count": len(real), "active_threads": active_threads,
        "notable": notable,
    }

def detect_signals(text: str) -> list[str]:
    """Return signal keywords found in text."""
    return [
        pat.pattern.replace(r"\b", "").replace("\\b", "")
        for pat in _SIGNAL_PATTERNS if pat.search(text)
    ]

def _extract_notable(messages: list[dict[str, Any]], limit: int = 5) -> list[dict]:
    """Score and rank notable messages by signal density."""
    scored: list[tuple[int, dict]] = []
    for msg in messages:
        text = msg.get("text", "")
        if not text or len(text) < 10:
            continue
        signals = detect_signals(text)
        if not signals:
            continue
        score = len(signals)
        if msg.get("reply_count", 0) > 0:
            score += 1
        if any(r.search(text) for r in _SIGNAL_PATTERNS[:6]):
            score += 2
        preview = text.split("\n")[0][:120]
        if len(text.split("\n")[0]) > 120:
            preview += "..."
        scored.append((score, {
            "text": preview, "signals": signals[:4],
            "user": msg.get("user", ""),
            "reply_count": msg.get("reply_count", 0),
        }))
    scored.sort(key=lambda x: x[0], reverse=True)
    return [item for _, item in scored[:limit]]

def _resolve_member(identifier: str, conn: sqlite3.Connection) -> Optional[dict]:
    """Resolve member by name, github, email, or ID."""
    if identifier.isdigit():
        row = conn.execute("SELECT * FROM members WHERE id = ?", (int(identifier),)).fetchone()
    else:
        row = conn.execute(
            "SELECT * FROM members WHERE LOWER(name) = LOWER(?) OR github = ? OR email = ?",
            (identifier, identifier, identifier),
        ).fetchone()
    return dict(row) if row else None

def _gather_full_context(member: dict, conn: sqlite3.Connection) -> str:
    """Gather comprehensive context about a member for LLM prompts."""
    parts = [f"Member: {member['name']}"]
    if member.get("title"):
        parts.append(f"Title: {member['title']}")
    if member.get("github"):
        parts.append(f"GitHub: {member['github']}")
    if member.get("email"):
        parts.append(f"Email: {member['email']}")

    # Flags
    flags = [r["flag"] for r in conn.execute(
        "SELECT flag FROM member_flags WHERE member_id = ?", (member["id"],)
    ).fetchall()]
    if flags:
        parts.append(f"Flags: {', '.join(flags)}")

    # Performance snapshots
    snapshots = conn.execute(
        """SELECT date, metrics, score FROM performance_snapshots
           WHERE member_id = ? ORDER BY date DESC LIMIT 10""",
        (member["id"],),
    ).fetchall()
    if snapshots:
        parts.append("\nPerformance snapshots:")
        for s in snapshots:
            metrics = json.loads(s["metrics"]) if s["metrics"] else {}
            parts.append(
                f"  {s['date']}: score={s['score']}, "
                f"commits={metrics.get('commits_count', 0)}, "
                f"prs={metrics.get('prs_merged', 0)}, "
                f"issues={metrics.get('issues_completed', 0)}"
            )

    # Meetings
    meetings = conn.execute(
        """SELECT date, summary, sentiment_score FROM meetings
           WHERE member_id = ? ORDER BY date DESC LIMIT 5""",
        (member["id"],),
    ).fetchall()
    if meetings:
        parts.append("\nRecent meetings:")
        for mtg in meetings:
            parts.append(f"  {mtg['date']} (sentiment: {mtg['sentiment_score'] or '?'})")
            if mtg["summary"]:
                parts.append(f"    {mtg['summary'][:300]}")

    # Open items
    items = conn.execute(
        """SELECT mi.kind, mi.content FROM meeting_items mi
           JOIN meetings m ON m.id = mi.meeting_id
           WHERE m.member_id = ? AND mi.status = 'open'
           ORDER BY mi.created_at DESC LIMIT 10""",
        (member["id"],),
    ).fetchall()
    if items:
        parts.append("\nOpen action items:")
        for item in items:
            parts.append(f"  - [{item['kind']}] {item['content']}")

    # Goals
    goals = conn.execute(
        "SELECT type, title, current_value, target_value, status FROM goals WHERE member_id = ? ORDER BY id",
        (member["id"],),
    ).fetchall()
    if goals:
        parts.append("\nGoals:")
        for g in goals:
            progress = ""
            if g["target_value"]:
                progress = f" ({g['current_value'] or 0}/{g['target_value']})"
            parts.append(f"  - [{g['type']}] {g['title']}{progress} [{g['status']}]")

    # Coaching entries
    entries = conn.execute(
        "SELECT kind, content, created_at FROM coaching_entries WHERE member_id = ? ORDER BY created_at DESC LIMIT 5",
        (member["id"],),
    ).fetchall()
    if entries:
        parts.append("\nCoaching history:")
        for e in entries:
            parts.append(f"  [{e['kind']}] {e['created_at']}: {e['content'][:200]}")

    return "\n".join(parts)

def cmd_config_show(args: argparse.Namespace) -> None:
    """Show current configuration."""
    cfg = load_config()
    data = cfg.model_dump()
    log_operation("config show")

    if getattr(args, "json", False):
        render_output(data, json_mode=True)
    else:
        lines = ["## Ascend Configuration\n"]
        for key, value in data.items():
            lines.append(f"  {key}: {value}")
        print_report("\n".join(lines))

def cmd_config_set(args: argparse.Namespace) -> None:
    """Set a configuration value."""
    try:
        cfg = set_config_value(args.key, args.value)
        log_operation("config set", args={"key": args.key, "value": args.value})
        if getattr(args, "json", False):
            render_output({"key": args.key, "value": getattr(cfg, args.key)}, json_mode=True)
        else:
            print_report(f"Set `{args.key}` = `{args.value}`")
    except KeyError as e:
        if getattr(args, "json", False):
            render_output({"error": str(e)}, json_mode=True)
        else:
            print_report(f"Error: {e}")

def _resolve_member_arg(member: str, conn: sqlite3.Connection) -> Optional[int]:
    """Resolve a --member argument to a member_id."""
    if member.isdigit():
        return int(member)
    row = conn.execute(
        "SELECT id FROM members WHERE LOWER(name) = LOWER(?) OR github = ?",
        (member, member),
    ).fetchone()
    return row["id"] if row else None

def cmd_meeting_show(args: argparse.Namespace) -> None:
    """Show full meeting details."""
    conn = _get_conn()
    row = conn.execute(
        """SELECT m.*, mem.name as member_name FROM meetings m
           LEFT JOIN members mem ON mem.id = m.member_id
           WHERE m.id = ?""",
        (args.id,),
    ).fetchone()

    if not row:
        conn.close()
        render_output(f"Error: meeting {args.id} not found")
        return

    items = conn.execute(
        "SELECT * FROM meeting_items WHERE meeting_id = ? ORDER BY kind, id",
        (args.id,),
    ).fetchall()
    conn.close()

    log_operation("meeting show", args={"id": args.id})

    if getattr(args, "json", False):
        data = dict(row)
        data["items"] = [dict(i) for i in items]
        render_output(data, json_mode=True)
    else:
        lines = [f"## Meeting {row['id']} — {row['date']}\n"]
        if row["member_name"]:
            lines.append(f"**Member:** {row['member_name']}")
        if row["summary"]:
            lines.append(f"\n### Summary\n\n{row['summary']}")
        if row["sentiment_score"] is not None:
            lines.append(f"\n**Sentiment:** {row['sentiment_score']:.2f}")
        if items:
            lines.append("\n### Items\n")
            for item in items:
                status = "x" if item["status"] == "closed" else " "
                lines.append(f"- [{status}] **{item['kind']}**: {item['content']}")
        if row["raw_text"]:
            lines.append(f"\n### Transcript\n\n{row['raw_text'][:2000]}")
            if len(row["raw_text"]) > 2000:
                lines.append(f"\n... ({len(row['raw_text'])} chars total)")
        render_output("\n".join(lines), copy=getattr(args, "copy", False))

