            messages=[{
                "role": "user",
                "content": f"Create PIP criteria for {member_name}.\n\nContext:\n{context}",
            }],
        )
        from ascend.summarizer import _parse_json
        parsed = _parse_json(response.content[0].text)
        if isinstance(parsed, list):
