def _extract_md_heading(content: str) -> Optional[str]:
    """Extract the first # heading from markdown."""
    for line in content.split("\n"):
        if line.startswith("# "):
            return line[2:].strip()
    return None

def _extract_md_field(content: str, field: str) -> Optional[str]:
    """Extract a **Field:** value from markdown."""
    pattern = rf"\*\*{field}:\*\*\s*(.+)"
    match = re.search(pattern, content)
    if match:
        return match.group(1).strip()
    return None

def _extract_md_section_first_line(content: str, section: str) -> Optional[str]:
    """Extract the first non-empty line after a ## Section heading."""
    lines = content.split("\n")
    in_section = False
    for line in lines:
        if line.strip().startswith(f"## {section}"):
            in_section = True
            continue
        if in_section:
            stripped = line.strip()
            if stripped.startswith("## "):
                break
            if stripped and not stripped.startswith("-"):
                return stripped
            if stripped.startswith("- "):
                return stripped[2:]
    return None

def _resolve_member(member: str, conn: sqlite3.Connection) -> Optional[dict]:
    """Resolve member by name, github, or ID. Returns dict or None."""
    if member.isdigit():
        row = conn.execute("SELECT id, name, github, email, personal_email FROM members WHERE id = ?", (int(member),)).fetchone()
    else:
        row = conn.execute(
            "SELECT id, name, github, email, personal_email FROM members WHERE LOWER(name) = LOWER(?) OR github = ?",
            (member, member),
        ).fetchone()
    return dict(row) if row else None

